# Create a Quick Access app segment (simplest — no app registration needed)
# Quick Access groups private app destinations into a single policy target

$quickAccess = @{
    displayName = 'Corp-Internal-Apps'
    applicationSegments = @(
        @{
            destinationType = 'fqdn'
            destinationHost = 'rdp.corp.contoso.com'
            ports = @('3389')
            protocol = 'tcp'
        },
        @{
            destinationType = 'fqdn'
            destinationHost = '*.internal.contoso.com'
            ports = @('443', '80')
            protocol = 'tcp'
        },
        @{
            destinationType = 'ipRange'
            destinationHost = '10.1.0.0'
            prefixSize = 24
            ports = @('22')  # SSH
            protocol = 'tcp'
        }
    )
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/beta/networkAccess/filteringProfiles' `
  -Body $quickAccess

# Create a Global Secure Access Enterprise Application for granular per-app CA policy
# Enterprise apps give each private resource its own CA policy target

# Step 1: Register the app in Entra ID
$app = @{
    displayName = 'Corp-SSH-Bastion'
    signInAudience = 'AzureADMyOrg'
    requiredResourceAccess = @()
    onPremisesPublishing = @{
        applicationServerTimeout = 'Default'
        externalUrl = 'https://corp-ssh-bastion.msappproxy.net'
        internalUrl = 'ssh://bastion.corp.contoso.com:22'
        isOnPremPublishingEnabled = $true
    }
} | ConvertTo-Json -Depth 5

# Step 2: Create CA policy targeting this specific Enterprise App
$caPolicy = @{
    displayName = 'Require-MFA-for-Corp-SSH'
    state = 'enabled'
    conditions = @{
        users        = @{ includeGroups = @('<infra-team-group-id>') }
        applications = @{ includeApplications = @('<enterprise-app-id>') }
    }
    grantControls = @{
        operator = 'OR'
        builtInControls = @('mfa', 'compliantDevice')
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' `
  -Body $caPolicy
